/** @format */

import React from "react";
import Logo from "../images/Accesss-Autonomy-Logo.ico";
import { Link } from "react-router-dom";
import ReactSwitch from "react-switch";
import Burger from "./components/BurgerMenu";
import {
  FaHome,
  FaChild,
  FaThLarge,
  FaGithub,
  FaLinkedinIn,
} from "react-icons/fa";

const Nav = (props) => {
  const toggleTheme = (event) => {
    props.onChangeSwitch(event);
  };




  return (
    <>
    <Burger />
    <div className="nav-main">
      <div id={"nav-main-logo"}>
        <img src={Logo} alt="AccessAutonomy Logo"></img>
      </div>
      <div id={"nav-main-list"}>
        <Link to="/">
          <FaHome />
        </Link>
        <Link to="/about">
          <FaChild />
        </Link>
        <Link to="/projects">
          <FaThLarge />
        </Link>
        <Link to="/blog">
          <FaGithub />
        </Link>
        <Link to="/contacts">
          <FaLinkedinIn />
        </Link>
        <div className="switch">
          <ReactSwitch
            value={props.themeToggled}
            onChange={toggleTheme}
            checked={props.themeToggled === "dark"}
          />
        </div>
      </div>
    </div>
    </>
  );
};

export default Nav;
